var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이봐, 아저씨.","JPN":"ちょっと、おじさん。","ENG":"Hey, mister.","TWN":"喂，大叔。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......왜 그러지?","JPN":"……なんだ？","ENG":"What is it?","TWN":"……怎麼了？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아무리 그래도 100kg이나 되는 이터니움을 개인이 구할 수 있을 리가 없잖아?","JPN":"いくら何でも、100kgものエタニウムを個人で入手できるわけないじゃない。","ENG":"Do you really think that an individual could get their hands on a hundred kilograms of Eternium?","TWN":"不管再怎麼說，100公斤的永恆之金，都不可能是區區個人能擁有的量吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"차라리 지금이라도 실비아나 카일에게 연락해 보는 게 낫지 않을까?","JPN":"今からでも、シルビアやカイルに連絡した方がいいんじゃないの？","ENG":"Don't you think it'd be better to contact Sylvia or Kyle about this?","TWN":"不如我們去聯絡希爾維亞和凱爾，這樣不是比較好？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"나도 그 생각을 안 해 본 건 아니지만......","JPN":"俺もその選択肢を考えてないわけではないが……","ENG":"Actually, that was the first thing that came to my mind,","TWN":"我也不是沒有想過這個辦法。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아마 무리일 거다.","JPN":"まあ、無理だろうな。","ENG":"but I doubt they could be of help.","TWN":"但恐怕行不通。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"지금 이터니움 국제 시세는 말 그대로 폭발 직전이야.","JPN":"今、エタニウムの国際相場は、いわば暴騰寸前の状態だ。","ENG":"The international price of Eternium is literally through the roof.","TWN":"現在永恆之金的國際行情，就如字面上一樣處於一觸即發的狀況。"},"stage":{"bg":"ETERNIUM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"로스트 쉽 파괴 작전, 대규모 침식 증후군 치료용 등으로 이터니움 요구량은 어마어마하게 커진 반면에 이터니움 채굴은 완전히 멈춰 버렸으니까.","JPN":"エタニウムの需要は、ロストシップの破壊作戦や侵食症候群の治療などで大幅に増えた一方で、\\nエタニウムの採掘は完全に止まっちまったからな。","ENG":"The Lost Ship annihilation, mass outbreak of Corruption Syndrome... The demand for Eternium is higher than ever before, whereas the mining of it came to a complete stop.","TWN":"在失落艦船的作戰、治療大規模侵蝕症候群等等的事情上，永恆之金需求量變得極大的同時，永恆之金的開採卻完全停擺了。"},"stage":{"bg":"ETERNIUM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"슬쩍 전해 들은 바에 따르면 이미 국가 전략 비축분의 재고도 간당간당한 모양이더군.","JPN":"人づてに聞いたんだが、国家戦略備蓄分の在庫もすでに残りわずかのようだ。","ENG":"One of my sources says that even the national strategic stockpile is empty.","TWN":"就我聽到的傳言，國家戰略儲備的庫存已經到了非常吃緊的狀況。"},"stage":{"bg":"ETERNIUM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"ETERNIUM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이런 상황에서 아무리 엘리트라고 해도 일개 특수부대원이 그런 엄청난 양의 이터니움을 꺼내 쓸 수 있을 리가 없어.","JPN":"こんな状況じゃあ、いくらエリートでも、そんな凄まじい量のエタニウムを調達できるわけない。","ENG":"It's hard to think that special forces agents, however capable they may be, could use so much Eternium at their discretion.","TWN":"在這種情況下，就算他們是菁英，但區區一個特殊部隊的隊員也不可能拿出這麼龐大的永恆之金啊。"},"stage":{"bg":"ETERNIUM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But…","TWN":"但是……"},"stage":{"bg":"ETERNIUM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그뿐이 아니야.","JPN":"それだけじゃない。","ENG":"That's not all.","TWN":"不只是這個原因。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"함부로 우리 계획을 노출했다간 리플레이서 놈들에게 정보가 샐지도 모른다.","JPN":"下手に俺たちの計画を話すと、リプレイサーどもに情報が漏れるかもしれないぞ。","ENG":"If we share our plan with anyone, it can leak out to the Replacers.","TWN":"如果輕易地公開我們的計畫，情報有可能會洩漏給克隆集團知道也不一定。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그랬다간 형이 목숨을 걸고 만들어 준 기회가 물거품이 될 거야.","JPN":"そんなことになれば、兄貴が命がけで作ってくれたチャンスが水の泡さ。","ENG":"Ian gave up his life to give us this chance. I won't let it be in vain.","TWN":"那樣的話，我哥賭上性命才創造出的機會，全部就泡湯了。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정보가 새다니...... 그럴 리가 있겠어?","JPN":"情報が漏れるなんて……そんなことある？","ENG":"Leak out? That's not going to happen.","TWN":"情報洩露啊……怎麼可能會有這種事呢？"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"누가 리플레이서의 편을 든다고......","JPN":"あのリプレイサーに味方するなんてあるわけ……","ENG":"Who's going to side with the Replacers now?","TWN":"有誰會站在克隆集團那邊啊……"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"명심해 둬, 아가씨.","JPN":"嬢ちゃん、肝に銘じておけ。","ENG":"Remember, young lady.","TWN":"記好了，小姐。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"리플레이서의 동조자는 정부에도, 관리국에도 있다.","JPN":"リプレイサーのスパイは、政府側にも、管理局にもいる。","ENG":"The Replacers have eyes and ears everywhere, whether it be the government or the Administration.","TWN":"不論是在政府還是管理局裡，都有克隆集團的異端者。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"영생을 위한 인간의 욕망을 우습게 보지 마.","JPN":"永生を求める人間の欲望を見くびるなよ。","ENG":"Never underestimate the human desire for eternal life.","TWN":"不要小看人類想得到永生的欲望。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"리플레이서 융합체가 되면 인간을 초월한 힘을 얻는 것은 물론, 질병이나 노화에서도 해방되는 것처럼 보이지.","JPN":"リプレイサー融合体になれば、人知を越える力を得るのはもちろん、\\n病気や老化からも解放された感覚になる。","ENG":"At a glance, even without the superhuman strength that it offers, becoming a Replacer hybrider seems to mean being free of disease and aging.","TWN":"一旦成為克隆融合體，不僅可以獲得超越人類的力量，還可以從疾病和老化中解放出來。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......마치 영원한 생명을 부여 받는 것처럼.","JPN":"……まるで永遠の命を与えられたかのようにな。","ENG":"As if you're being given eternal life.","TWN":"……就像被賦予了永遠的生命一樣。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그게 정말이야?","JPN":"そ、それ本当なの？","ENG":"I-is that the truth?","TWN":"這、這是真的嗎？"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럴 리가 있나?","JPN":"そんなわけあるか。","ENG":"How could that possibly be the truth?","TWN":"怎麼可能呢？"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"애초에 리플레이서 인자 적합체도 적은 편이야.","JPN":"そもそもリプレイサーファクターの適合体も多くないんだ。","ENG":"To start with, there are very few people that are physically compatible with Replacer Factors.","TWN":"本來，克隆因子的適性體就很少。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"설사 그 낮은 확률을 뚫고 성공적으로 융합체가 되었다고 해도 끝이 아니지.","JPN":"たとえ、あの低い確率を突破して問題なく融合体になれたとしても、そこで終わりじゃない。","ENG":"Even if you were to belong in that ridiculously small number of people and be converted into a hybrider, it's not the end.","TWN":"即使突破低機率的難關，成功地變成融合體，這也不意味著結束。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내가 추가로 입수한 자료에 따르면 육체의 유지를 위해서는 주기적으로 리플레이서 인자를 제공받아야 해.","JPN":"俺が追加で手に入れた資料によると、肉体の維持のためには、\\n定期的にリプレイサーファクターを提供してもらう必要がある。","ENG":"According to my recent data, hybriders must be supplied with Replacer Factors on a regular basis.","TWN":"根據我追加獲得的資料顯示，這些人為了維持肉體，需要定期提供克隆因子。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"주기적으로.......?","JPN":"定期的に……？","ENG":"On a regular basis?","TWN":"定期……?"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 제공받지 못하면 어떻게 되는데?","JPN":"提供されなかったら、どうなるの？","ENG":"What happens if they are not supplied?","TWN":"那如果沒有定期獲得供給的話會怎麼樣？"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뻔한 걸 왜 묻고 그러나?","JPN":"そんなの決まってるじゃないか。","ENG":"What do you think?","TWN":"為什麼要問這種顯而易見的事情？"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"당연히 침식체로 붕괴하는 거지.","JPN":"当然、侵食体になっちまうのさ。","ENG":"They collapse into C.O.s.","TWN":"那當然會變成侵蝕體。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"리플레이서 인자라는 건, 말 그대로 불량품이야.","JPN":"つまりリプレイサーファクターってのは、不良品なんだ。","ENG":"Replacer factors are literally defective.","TWN":"所謂的克隆因子，顧名思義就是不良品。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만...... 과대광고에 낚이는 얼간이들은 어디든지 있는 법이니까.","JPN":"けど、甘言に釣られるバカどもはどこにでもいるからな。","ENG":"But there are always fools who fall for false advertisement.","TWN":"但……到處都有會被誇大廣告釣到的笨蛋啊。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그것도 어쩔 수 없는 거지.","JPN":"それもまあ、しょうがないよな。","ENG":"It's just how the world goes around.","TWN":"那也沒有辦法。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이봐요, 용병 씨.","JPN":"ちょっと、傭兵さん。","ENG":"Hey, Mr. Mercenary.","TWN":"喂，傭兵先生。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"벌써 한참 온 것 같은데 어디까지 가야 하는 거죠?","JPN":"出発からだいぶ経ってますけど、どこまで行くんですか？","ENG":"Haven't we traveled long enough? How much longer do we have to go?","TWN":"我們都已經走了好一陣子了，到底要走到哪啊？"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......이제 거의 다 왔어.","JPN":"……もうそろそろ着く。","ENG":"We're almost there.","TWN":"……快到了。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저기로군.","JPN":"あそこだ。","ENG":"That's the place.","TWN":"就是那裡吧。"},"stage":{"bg":"VEHICLE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어...... 왠지 불길한 소리가 들리는데요?","JPN":"あ……なんだか不吉な音がしますね。","ENG":"Um... Is it just me, or do you hear an ominous sound?","TWN":"呃……我總覺得好像聽到了什麼不祥的聲音。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"당연히 불길하지. 여긴 로스트 쉽 재난지역이거든.","JPN":"当然だ。ここはロストシップの災害地域だからな。","ENG":"I hear it. This is a Lost Ship Disaster area.","TWN":"當然不祥了，因為這裡是失落艦船的受災區。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......하하하. 이젠 뭐 놀랍지도 않네요.","JPN":"……あはは、もはや何の驚きもありません。","ENG":"Hah hah... I'm not even surprised anymore.","TWN":"……哈哈哈，我已經不會再感到驚訝了。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"세계를 구하는 데 이 정도 위기는 기본으로 닥쳐 줘야 하는 거 아니겠어요?","JPN":"世界を救うためなら、これくらいの危機はどうってことないですよね。","ENG":"Saving the whole world doesn't come without hardships and adversities, does it?","TWN":"為了拯救世界，這種程度的危機應該也不成問題吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"경찰 아가씨도 적응이 빠른 것 같아 기쁘군.","JPN":"警察の嬢ちゃんも手慣れたもんだな。","ENG":"I'm glad you're quick to adapt, officer lady.","TWN":"員警小姐適應得如此之快，讓我很欣慰呢。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그보다 만나야 할 사람들을 찾은 것 같아.","JPN":"それより、目当ての奴らを見つけたようだ。","ENG":"Anyway, I think we've found the people we're supposed to meet.","TWN":"話說回來，我們好像找到我們要見的那些人了。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어이!","JPN":"おい！","ENG":"Hey!","TWN":"喂！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"혹시 도움이 필요한가?!","JPN":"ひょっとして助けが必要か！？","ENG":"Do you need help?","TWN":"你們需要幫助嗎？！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐?! 누군지는 모르겠지만 쓸데없는 소리 말고 꺼져!","JPN":"何だ！？　誰だか知らねえけど、失せやがれ！","ENG":"Huh? Whoever you are, shut up and get lost!","TWN":"什麼？！我不認識你們，廢話少說立刻滾開！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"여긴 우리 구역이라고!","JPN":"ここは俺たちの担当区域なんだよ！","ENG":"This is our territory!","TWN":"這裡是我們的地盤！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......넌 대체 무슨 자신감으로 하는 소리야?","JPN":"……あんた、その自信はいったいどこからくるのよ？","ENG":"Why are you being so cocky?","TWN":"……你到底是哪來的自信說這種話啊？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"저놈들 숫자 안 보여?","JPN":"敵があんなにうじゃうじゃいるのに、見えてないわけ？","ENG":"Don't you see how outnumbered we are?","TWN":"你沒看到那些傢伙有多少人嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"지금은 풋내기 신병이 와도 쌍수 벌려 환영할 판이라고!","JPN":"今は猫の手も借りたいところなの！","ENG":"We should be welcoming anyone who can help us!","TWN":"現在就算是菜鳥新兵來了，也要舉雙手歡迎啊！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"흐음. 환영해 주니 고맙군.","JPN":"うむ、歓迎してもらえてるようだな。","ENG":"Hmm. It's pleasant to know that you're glad to see us.","TWN":"嗯。感謝妳歡迎我們。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이봐, 용병씨! 누군진 모르겠지만 도와 줄 거면 빨리 도와달라고!","JPN":"ちょっと、そこの傭兵さん！　誰だか知らないけど、手伝ってくれるなら早くしてよ！","ENG":"Hey, Mr. Merc! I don't know you, but be quick if you're trying to help!","TWN":"喂，傭兵先生！雖然不知道你們是誰，但如果你們要幫我們的話，就快點幫吧！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그리고 오르카!","JPN":"それと、オルカ！","ENG":"And you, Orca!","TWN":"然後，奧爾卡！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"너 또 폭주해서 혼자 달려들지 말고 우리랑 보조를 맞춰! 알았지?!","JPN":"あんたね、また勝手に一人で突っ走らないで、足並み揃えてよね！　わかった！？","ENG":"I'll kill you if you go mad and run into them on your own again! Work with us! Get it?","TWN":"妳不要又暴走一個人亂衝，要配合我們的步調！懂嗎！？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......알았다.","JPN":"……わかった。","ENG":"Okay.","TWN":"……知道了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"침식체는 죽......!","JPN":"侵食体は殺……！","ENG":"Corrupted Objects, I must ki—","TWN":"侵蝕體殺……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카!!","JPN":"オルカ！！","ENG":"Orca!","TWN":"奧爾卡！！！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"아, 아니...... 박살낸다!","JPN":"い、いや……壊してやる！","ENG":"I-I mean... I must smash!","TWN":"啊，不是……粉碎！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"후우...... 뭐가 다른 건지 원......","JPN":"ふう……それじゃあ何が違うかわからないわよ……","ENG":"*Sigh* What's the difference?","TWN":"呼……這有什麼不同嗎 ……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다들 들었지?","JPN":"みんな聞いたよな？","ENG":"You heard her.","TWN":"大家都聽到了吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"환영 받는 손님이 되려면 주인의 걱정거리를 같이 처리해 줘야 하는 법이지.","JPN":"ホストに歓迎される客になるには、心配事を一緒に片づけてやらんとな。","ENG":"If you want to be welcomed as a guest, you need to lend a hand when the host is in trouble.","TWN":"想要成為受歡迎的客人，就必須解決主人的煩惱。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다들 가자고!","JPN":"みんな、行くぞ！","ENG":"Let's move!","TWN":"大家上啊！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};